-- =============================================================
-- Migration 126 — People directory (curated staff list, ~168 people).
-- Merged from the Notion People export + the Azure AD export (official
-- job titles). Used to auto-fill a user's profile on first login and to
-- list everyone under admin > Users even before they've signed in.
-- =============================================================

BEGIN;

CREATE TABLE IF NOT EXISTS public.people_directory (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email         TEXT UNIQUE NOT NULL,
  full_name     TEXT,
  first_name    TEXT,
  last_name     TEXT,
  business_unit TEXT,
  job_title     TEXT,
  phone         TEXT,
  language      TEXT,
  department    TEXT,
  person_type   TEXT,
  is_active     BOOLEAN NOT NULL DEFAULT TRUE,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE public.people_directory ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Staff read directory" ON public.people_directory;
CREATE POLICY "Staff read directory" ON public.people_directory FOR SELECT
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role IN ('admin','manager')));

DROP POLICY IF EXISTS "Admins manage directory" ON public.people_directory;
CREATE POLICY "Admins manage directory" ON public.people_directory FOR ALL
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'))
  WITH CHECK (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));

-- Also readable by the signed-in person about themselves (for first-login
-- profile auto-fill) — matched on their own email.
DROP POLICY IF EXISTS "Read own directory row" ON public.people_directory;
CREATE POLICY "Read own directory row" ON public.people_directory FOR SELECT
  USING (lower(email) = lower(COALESCE((auth.jwt() ->> 'email'), '')));


COMMIT;
